&1+12+123+1234+12345+123456+1234567+12345678\\
&\qquad\equiv 1+2+3+4+0+1+2+3 \\ &\qquad\equiv 16 \\ &\qquad\equiv \boxed{1} \pmod{5}.\end{align*}

